### 6. js/auth.js
Auth state management:

```javascript
var RCAuth = (function() {
    var currentUser = null;

    return {
        getUser: function() { return currentUser; },
        setUser: function(user) { currentUser = user; },
        isLoggedIn: function() { return currentUser !== null; },
        hasRole: function(role) { return currentUser && currentUser.roles && currentUser.roles.indexOf(role) !== -1; },
        isAdmin: function() { return this.hasRole('admin'); },
        isModerator: function() { return this.hasRole('moderator') || this.isAdmin(); },
        hasPermission: function(perm) { ... },

        // Check auth on app start
        init: function() {
            return RCApi.me().then(function(data) {
                currentUser = data.user;
                return currentUser;
            }).catch(function() {
                currentUser = null;
                return null;
            });
        },

        login: function(email, password) {
            return RCApi.login(email, password).then(function(data) {
                currentUser = data.user;
                return currentUser;
            });
        },

        logout: function() {
            return RCApi.logout().then(function() {
                currentUser = null;
            });
        }
    };
})();
```

