### 8. js/router.js
Hash-based router:

```javascript
var RCRouter = (function() {
    var routes = {};
    var currentPage = null;

    return {
        register: function(pattern, handler) {
            routes[pattern] = handler;
        },

        navigate: function(hash) {
            window.location.hash = hash;
        },

        resolve: function() {
            var hash = window.location.hash.slice(1) || '/';
            var container = document.getElementById('app-content');
            var header = document.getElementById('app-header');

            // Public routes (no auth required)
            var publicRoutes = ['/login', '/register'];
            var isPublic = publicRoutes.indexOf(hash.split('?')[0]) !== -1;

            if (!isPublic && !RCAuth.isLoggedIn()) {
                window.location.hash = '#/login';
                return;
            }

            // Show/hide header for auth pages
            header.style.display = isPublic ? 'none' : '';
            document.getElementById('app-body').className = isPublic ? 'rc-body rc-body-auth' : 'rc-body rc-body-app';

            // Match route
            // Support: /listings/:id, /orders/:id, /listings/:id/versions, etc.
            // Try exact match first, then pattern match

            // Route matching with params extraction
            // Call matched handler with (container, params)

            // If no match, show 404 page
        },

        start: function() {
            window.addEventListener('hashchange', function() {
                RCRouter.resolve();
            });
            RCRouter.resolve();
        }
    };
})();
