        // Search input with debounced suggestions
        var searchInput = document.getElementById('search-input');
        var suggestionsDiv = document.getElementById('search-suggestions');
        var debounceTimer = null;

        searchInput.addEventListener('input', function() {
            clearTimeout(debounceTimer);
            var q = this.value.trim();
            if (q.length < 2) { suggestionsDiv.style.display = 'none'; return; }
            debounceTimer = setTimeout(function() {
                RCApi.getSuggestions(q).then(function(data) {
                    if (data.suggestions && data.suggestions.length) {
                        suggestionsDiv.innerHTML = data.suggestions.map(function(s) {
                            return '<div class="rc-suggestion-item">' + RCUtil.escapeHtml(s) + '</div>';
                        }).join('');
                        suggestionsDiv.style.display = 'block';
                        // Click handler for each suggestion
                        suggestionsDiv.querySelectorAll('.rc-suggestion-item').forEach(function(item) {
                            item.addEventListener('click', function() {
                                searchInput.value = this.textContent;
                                suggestionsDiv.style.display = 'none';
                                doSearch();
                            });
                        });
                    } else {
                        suggestionsDiv.style.display = 'none';
                    }
                });
            }, 300);
        });

        // Search on Enter
        searchInput.addEventListener('keypress', function(e) {
            if (e.key === 'Enter') { e.preventDefault(); doSearch(); }
        });

