        // Filter apply handler
        // Load listings function with loading skeleton
        // Render listing cards with highlights
        // Did-you-mean prompt
        // No-results fallback with recent active listings
        // Pagination

        function doSearch() {
            currentQuery = searchInput.value.trim();
            if (currentQuery) RCUtil.addSearchHistory(currentQuery);
            currentPage = 1;
            loadListings();
        }

        function loadListings() {
            var resultsDiv = document.getElementById('listings-results');
            resultsDiv.innerHTML = RCUtil.skeleton(4); // Loading state

            var params = { page: currentPage, per_page: 12, sort: currentSort };
            if (currentQuery) params.q = currentQuery;
            if (currentFilters.vehicle_type) params.vehicle_type = currentFilters.vehicle_type;
            if (currentFilters.rider_count_min) params.rider_count_min = currentFilters.rider_count_min;
            if (currentFilters.rider_count_max) params.rider_count_max = currentFilters.rider_count_max;
            if (currentFilters.status) params.status = currentFilters.status;

            RCApi.getListings(params).then(function(data) {
                if (!data.listings || data.listings.length === 0) {
                    // Check did_you_mean
                    var dymDiv = document.getElementById('did-you-mean');
                    if (data.did_you_mean) {
                        dymDiv.innerHTML = 'Did you mean: <a href="javascript:;" class="rc-dym-link">' + 
                            RCUtil.escapeHtml(data.did_you_mean) + '</a>?';
                        dymDiv.style.display = 'block';
                        dymDiv.querySelector('.rc-dym-link').addEventListener('click', function() {
                            searchInput.value = data.did_you_mean;
                            doSearch();
                        });
                    }

                    // Show no-results with fallback
                    if (data.recent_active && data.recent_active.length) {
                        resultsDiv.innerHTML = 
                            '<div class="rc-empty-state"><p>No rides found for "' + RCUtil.escapeHtml(currentQuery) + 
                            '". Here are some recently active listings:</p></div>' +
                            renderListingCards(data.recent_active, false);
                    } else {
                        resultsDiv.innerHTML = RCUtil.emptyState(
                            'No trip requests yet. Be the first to post one!',
                            'Post a Trip Request', '#/listings/create'
                        );
                    }
                    return;
                }

                document.getElementById('did-you-mean').style.display = 'none';
                resultsDiv.innerHTML = 
                    '<div class="rc-results-count">' + data.meta.total + ' results</div>' +
                    renderListingCards(data.listings, !!currentQuery);

                // Pagination
                RCUtil.renderPagination('listings-pagination', data.meta.total, data.meta.page, data.meta.per_page, function(page) {
                    currentPage = page;
                    loadListings();
                });
            }).catch(function(err) {
                resultsDiv.innerHTML = '<div class="rc-empty-state rc-error-state"><p>Failed to load listings: ' + 
                    RCUtil.escapeHtml(err.message) + '</p></div>';
            });
        }

        function renderListingCards(listings, showHighlights) {
            return '<div class="rc-listing-grid">' + listings.map(function(l) {
                var title = showHighlights && l.highlight && l.highlight.title ? l.highlight.title : RCUtil.escapeHtml(l.title);
                var desc = showHighlights && l.highlight && l.highlight.description ? l.highlight.description : RCUtil.escapeHtml(RCUtil.truncate(l.description || '', 120));
                var tags = (l.tags || []).map(function(t) { return '<span class="rc-tag-chip">' + RCUtil.escapeHtml(t) + '</span>'; }).join('');

                return '<div class="rc-listing-card layui-card">' +
                    '<div class="layui-card-header">' +
                    '  <a href="#/listings/' + l.id + '" class="rc-listing-title">' + title + '</a>' +
                    '  ' + RCUtil.statusBadge(l.status) +
                    '</div>' +
                    '<div class="layui-card-body">' +
                    '  <div class="rc-listing-meta">' +
                    '    <span><strong>Pickup:</strong> ' + RCUtil.escapeHtml(RCUtil.truncate(l.pickup_address, 40)) + '</span>' +
                    '    <span><strong>Drop-off:</strong> ' + RCUtil.escapeHtml(RCUtil.truncate(l.dropoff_address, 40)) + '</span>' +
                    '  </div>' +
                    '  <div class="rc-listing-details">' +
                    '    <span class="rc-detail-item">' + l.rider_count + ' rider(s)</span>' +
                    '    <span class="rc-detail-item">' + (l.vehicle_type || '').toUpperCase() + '</span>' +
                    '    <span class="rc-detail-item">' + RCUtil.formatTime12h(l.time_window_start) + ' - ' + RCUtil.formatTime12h(l.time_window_end) + '</span>' +
                    '  </div>' +
                    '  <div class="rc-listing-desc">' + desc + '</div>' +
                    '  <div class="rc-listing-tags">' + tags + '</div>' +
                    '  <div class="rc-listing-footer">' +
                    '    <span class="layui-word-aux">by ' + RCUtil.escapeHtml(l.user.name) + ' &middot; ' + RCUtil.formatRelative(l.created_at) + '</span>' +
                    '    <span class="rc-listing-stats">' + (l.view_count || 0) + ' views &middot; ' + (l.favorite_count || 0) + ' favorites</span>' +
                    '  </div>' +
                    '</div></div>';
            }).join('') + '</div>';
        }

        // Init
        renderSearchHistory();
        currentFilters.status = 'active';
        loadListings();
    }
};
